module mux_4to1 (
    input a,
    input b,
    input c,
    input d,
    input [1:0] sel,
    output y
);

    // 4-to-1 MUX logic
    wire neg_mux_output = (sel == 2'b00);
    assign y = neg_mux_output ? a : (sel == 2'b01) ? b :
               (sel == 2'b10) ? c :
                                d;

endmodule
